export async function signIn(email: string, password: string) {
  const user = await findUserByEmail(email);
  if (!user) throw new AuthenticationError("Invalid credentials");

  const valid = await verifyPassword(password, user.password_hash);
  if (!valid) throw new AuthenticationError("Invalid credentials");

  const teams = await listUserTeams(user.id);
  const firstTeam = teams[0];

  const token = signToken({
    sub: user.id,
    email: user.email,
    teamId: firstTeam?.id ?? "",
    role: "owner",
  });

  await setSession(token);
  return { user, token };
}
```



The function handles user authentication by verifying email and password credentials, retrieving the user's teams, generating an authentication token with the "owner" role, and establishing a session.

